sys_script_include.script:
var Task_Business_Rules = Class.create();
Task_Business_Rules.prototype = {
    initialize: function() {
		this.tcs = new TaskerCommonScriptingMethods();
    },

	stateChangeWorkNote: function(current, previous){
		// if the states are the same do not add to the worknote
		if(current.state == previous.state)
			return;
		var workNote;
		if(previous.getDisplayValue('state') == ''){
			workNote = gs.getMessage('State created in state {0}. ', [current.getDisplayValue('state')]);
		} else{
			workNote = gs.getMessage('State changed from {0} to {1}. ', [previous.getDisplayValue('state'), current.getDisplayValue('state')]);
		}

		switch(current.state){
			case this.tcs.UNASSIGNED_STATE:
				switch (previous.state){
					case this.tcs.REJECTED_ASSIGNMENT_STATE, this.tcs.REJECTED_PRIMARY_ASSIGNEE_STATE:
						workNote += gs.getMessage('\n{0} was updated by {1}\n Previous {2}:\n New {3}: {4}',
								[current.getLabel('primary_assignee'), gs.getUserDisplayName(), current.getLabel('primary_assignee'),
									current.getLabel('primary_assignee'),current.getDisplayValue('primary_assignee')]);
						break;
					case this.tcs.WORK_IN_PROGRESS_STATE, this.tcs.IN_REVIEW_STATE, this.tcs.REWORK_STATE:
						workNote += gs.getMessage('\n{0} was updated by {1}\n Previous {2}:\n New {3}: {4}',
								[current.getLabel('assigned_to'), gs.getUserDisplayName(), current.getLabel('assigned_to'),
									current.getLabel('assigned_to'),current.getDisplayValue('assigned_to')]);
						break;
					case this.tcs.ASSIGNED_STATE:
						// nothing additoinal here, only from to is required
						break;
				}
				break;
			case this.tcs.ASSIGNED_STATE:
				switch (previous.state){
					case this.tcs.REJECTED_ASSIGNMENT_STATE, this.tcs.UNASSIGNED_STATE:
						workNote += gs.getMessage('\n{0} was updated by {1}\n Previous {2}:\n New {3}: {4}',
								[current.getLabel('assigned_to'), gs.getUserDisplayName(), current.getLabel('assigned_to'),
									current.getLabel('assigned_to'),current.getDisplayValue('assigned_to')]);
						break;
					case this.tcs.REJECTED_PRIMARY_ASSIGNEE_STATE:
						workNote += gs.getMessage('\n{0} was updated by {1}\n Previous {2}:\n New {3}: {4}',
								[current.getLabel('primary_assignee'), gs.getUserDisplayName(), current.getLabel('primary_assignee'),
									current.getLabel('primary_assignee'),current.getDisplayValue('primary_assignee')]);
						workNote += gs.getMessage('\n{0} was updated by {1}\n Previous {2}:\n New {3}: {4}',
								[current.getLabel('assigned_to'), gs.getUserDisplayName(), current.getLabel('assigned_to'),
									current.getLabel('assigned_to'),current.getDisplayValue('assigned_to')]);
						break;
					case this.tcs.ACCEPTED_STATE:
						// nothing additoinal here, only from to is required
						break;
				}
				break;
			case this.tcs.ACCEPTED_STATE:
				switch (previous.state){
					case this.tcs.WORK_IN_PROGRESS_STATE:
						// nothing additoinal here, only from to is required
						break;
				}

				break;
			case this.tcs.REJECTED_PRIMARY_ASSIGNEE_STATE:
				switch (previous.state){
					case this.tcs.UNASSIGNED_STATE_STATE:
						workNote += gs.getMessage('\n{0} was updated by {1}\n Previous {2}:{3}\n New {3}: {4}',
								[current.getLabel('primary_assignee'), gs.getUserDisplayName(), current.getLabel('primary_assignee'),
								previous.getDisplayValue('primary_assignee'),current.getLabel('primary_assignee'),
								current.getDisplayValue('primary_assignee')]);
				}
				break;
			case this.tcs.WORK_IN_PROGRESS_STATE:
				switch (previous.state){
					case this.tcs.ASSIGNED_STATE, this.tcs.ACCEPTED_STATE:
						// nothing additoinal here, only from to is required
						break;
					case this.tcs.IN_REVIEW_STATE:
						// nothing additoinal here, only from to is required
						break;
				}
				break;
			case this.tcs.IN_REVIEW_STATE:
				switch (previous.state){
					case this.tcs.ASSIGNED_STATE, this.tcs.ACCEPTED_STATE, this.tcs.WORK_IN_PROGRESS_STATE, this.tcs.REWORK_STATE:
						workNote += gs.getMessage('\n{0}  has been sent to review by {1}: {2}',
								[current.getDisplayValue('number'), gs.getUserDisplayName(), current.getDisplayValue('response')]);
						break;
				}
				break;
			case this.tcs.REWORK_STATE:
				switch (previous.state){
					case this.tcs.IN_REVIEW_STATE:
						workNote += gs.getMessage('\n{0}  has been sent to rework by {1}: {2}',
								[current.getDisplayValue('number'), gs.getUserDisplayName(), current.getDisplayValue('comments_dt')]);
						break;
					case this.tcs.WORK_IN_PROGRESS_STATE:
						// nothing additoinal here, only from to is required
						break;
				}
				break;
			case this.tcs.COMPLETED_STATE, this.tcs.COMPLETED_INCOMPLETE_STATE:
				switch (previous.state){
						case this.tcs.ASSIGNED_STATE, this.tcs.ACCEPTED_STATE, this.tcs.WORK_IN_PROGRESS_STATE, this.tcs.IN_REVIEW_STATE, this.tcs.REWORK_STATE:
						// nothing additoinal here, only from to is required
						break;
				}
				break;
			case this.tcs.CANCELLED_STATE:
				workNote += gs.getMessage('\nThis task has been cancelled by {0}: {1}',
							[gs.getUserDisplayName(), current.getDisplayValue('u_cancellation_reason')]);
				break;				

		}
		return workNote;
	},

    type: 'Task_Business_Rules'
};
